'use server';

/**
 * @fileOverview AI-powered tool that analyzes incident reports to flag potentially unsafe routes or driver behaviors.
 *
 * - analyzeRouteSafety - A function that handles the route safety analysis process.
 * - AnalyzeRouteSafetyInput - The input type for the analyzeRouteSafety function.
 * - AnalyzeRouteSafetyOutput - The return type for the analyzeRouteSafety function.
 */

import {ai} from '@/ai/genkit';
import {z} from 'genkit';

const AnalyzeRouteSafetyInputSchema = z.object({
  incidentReports: z
    .string()
    .describe('A list of incident reports, each including route, driver, and description of the incident.'),
});
export type AnalyzeRouteSafetyInput = z.infer<typeof AnalyzeRouteSafetyInputSchema>;

const AnalyzeRouteSafetyOutputSchema = z.object({
  unsafeRoutes: z
    .string()
    .describe('A list of potentially unsafe routes identified from the incident reports.'),
  driverBehaviors: z
    .string()
    .describe('A list of potentially unsafe driver behaviors identified from the incident reports.'),
  summary: z.string().describe('A summary of the analysis of the incident reports.'),
});
export type AnalyzeRouteSafetyOutput = z.infer<typeof AnalyzeRouteSafetyOutputSchema>;

export async function analyzeRouteSafety(input: AnalyzeRouteSafetyInput): Promise<AnalyzeRouteSafetyOutput> {
  return analyzeRouteSafetyFlow(input);
}

const prompt = ai.definePrompt({
  name: 'analyzeRouteSafetyPrompt',
  input: {schema: AnalyzeRouteSafetyInputSchema},
  output: {schema: AnalyzeRouteSafetyOutputSchema},
  prompt: `You are an AI assistant specializing in analyzing safety incident reports to identify potentially unsafe routes and driver behaviors.

  Analyze the following incident reports and provide a summary of the analysis, a list of potentially unsafe routes, and a list of potentially unsafe driver behaviors.

  Incident Reports:
  {{incidentReports}}`,
});

const analyzeRouteSafetyFlow = ai.defineFlow(
  {
    name: 'analyzeRouteSafetyFlow',
    inputSchema: AnalyzeRouteSafetyInputSchema,
    outputSchema: AnalyzeRouteSafetyOutputSchema,
  },
  async input => {
    const {output} = await prompt(input);
    return output!;
  }
);
